100	function formatTime(dateStr) {
101	  if (!dateStr) return "--:--:--";
102	  try {
103	    const d = new Date(dateStr);
104	    if (isNaN(d.getTime())) return "--:--:--";
105	    return d.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
106	  } catch {
107	    return "--:--:--";
108	  }
109	}
