111	function formatDate(dateStr) {
112	  if (!dateStr) return "";
113	  try {
114	    const d = new Date(dateStr);
115	    if (isNaN(d.getTime())) return "";
116	    return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
117	  } catch {
118	    return "";
119	  }
120	}
