122	function timeAgo(dateStr) {
123	  if (!dateStr) return "";
124	  try {
125	    const d = new Date(dateStr);
126	    const now = new Date();
127	    const diff = now - d;
128	    if (diff < 0) return "just now";
129	    if (diff < 60000) return `${Math.floor(diff / 1000)}s ago`;
130	    if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
131	    if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
132	    return `${Math.floor(diff / 86400000)}d ago`;
133	  } catch {
134	    return "";
135	  }
136	}
