1626	function formatFinancialValue(val) {
1627	  if (val == null) return "\u2014";
1628	  const abs = Math.abs(val);
1629	  const sign = val < 0 ? "-" : "";
1630	  if (abs >= 1e12) return sign + "$" + (abs / 1e12).toFixed(2) + "T";
1631	  if (abs >= 1e9) return sign + "$" + (abs / 1e9).toFixed(2) + "B";
1632	  if (abs >= 1e6) return sign + "$" + (abs / 1e6).toFixed(2) + "M";
1633	  if (abs >= 1e3) return sign + "$" + (abs / 1e3).toFixed(2) + "K";
1634	  return sign + "$" + abs.toFixed(2);
1635	}
