1637	function renderCompanyFinancials(data) {
1638	  const body = $("#company-profile-body");
1639	  if (!body) return;
1640	
1641	  const fin = data.financials;
1642	  const earnings = data.earnings || [];
1643	
1644	  // Check if there's any meaningful data
1645	  const hasFinancials = fin && (fin.revenue != null || fin.net_income != null || fin.eps != null);
1646	  const hasEarnings = earnings.length > 0 && earnings.some((e) => e.actual_eps != null);
1647	
1648	  if (!hasFinancials && !hasEarnings) {
1649	    body.innerHTML = `<div class="cp-no-data">
1650	      <div class="cp-no-data-icon">\u2014</div>
1651	      <p>No financial data available</p>
1652	      <span>Financial data is not available for this ticker (e.g., ETFs, indices).</span>
1653	    </div>`;
1654	    return;
1655	  }
1656	
1657	  // Key metrics section
1658	  const periodLabel = fin && fin.fiscal_period && fin.fiscal_year
1659	    ? `${fin.fiscal_period} ${fin.fiscal_year}` : "";
1660	
1661	  const metricsHtml = hasFinancials ? `
1662	    ${periodLabel ? `<div class="cp-fin-period">Latest Quarter: ${escapeHtml(periodLabel)}</div>` : ""}
1663	    <div class="cp-fin-metrics">
1664	      <div class="detail-metric">
1665	        <div class="detail-metric-label">Revenue</div>
1666	        <div class="detail-metric-value">${formatFinancialValue(fin.revenue)}</div>
1667	      </div>
1668	      <div class="detail-metric">
1669	        <div class="detail-metric-label">Net Income</div>
1670	        <div class="detail-metric-value">${formatFinancialValue(fin.net_income)}</div>
1671	      </div>
1672	      <div class="detail-metric">
1673	        <div class="detail-metric-label">EPS</div>
1674	        <div class="detail-metric-value">${fin.eps != null ? "$" + fin.eps.toFixed(2) : "\u2014"}</div>
1675	      </div>
1676	      <div class="detail-metric">
1677	        <div class="detail-metric-label">P/E Ratio</div>
1678	        <div class="detail-metric-value">${fin.pe_ratio != null ? fin.pe_ratio.toFixed(1) + "x" : "\u2014"}</div>
1679	      </div>
1680	    </div>` : "";
1681	
1682	  // Earnings bar chart section (last 4 quarters, chronological order)
1683	  let chartHtml = "";
1684	  if (hasEarnings) {
1685	    const chronological = [...earnings].reverse();
1686	    const maxAbs = Math.max(...chronological.map((e) => Math.abs(e.actual_eps || 0)), 0.01);
1687	
1688	    const barsHtml = chronological.map((e) => {
1689	      const eps = e.actual_eps;
1690	      if (eps == null) return "";
1691	      const pct = Math.min(Math.abs(eps) / maxAbs * 100, 100);
1692	      const isPositive = eps >= 0;
1693	      const barClass = isPositive ? "cp-bar-positive" : "cp-bar-negative";
1694	      const label = `${e.fiscal_period} ${String(e.fiscal_year).slice(-2)}`;
1695	      const hasEstimate = e.estimated_eps != null;
1696	      const beat = hasEstimate && eps >= e.estimated_eps;
1697	      const colorClass = hasEstimate ? (beat ? "cp-bar-beat" : "cp-bar-miss") : barClass;
1698	
1699	      return `<div class="cp-bar-col">
1700	        <div class="cp-bar-value ${colorClass}">$${eps.toFixed(2)}</div>
1701	        <div class="cp-bar-track">
1702	          <div class="cp-bar-fill ${colorClass}" style="height:${pct}%"></div>
1703	        </div>
1704	        <div class="cp-bar-label">${escapeHtml(label)}</div>
1705	        ${hasEstimate ? `<div class="cp-bar-est">Est: $${e.estimated_eps.toFixed(2)}</div>` : ""}
1706	      </div>`;
1707	    }).join("");
1708	
1709	    chartHtml = `
1710	    <div class="cp-fin-chart-section">
1711	      <div class="cp-desc-label">Earnings Per Share — Last 4 Quarters</div>
1712	      <div class="cp-bar-chart">${barsHtml}</div>
1713	      <div class="cp-bar-legend">
1714	        <span class="cp-legend-item"><span class="cp-legend-dot cp-bar-positive"></span>Positive</span>
1715	        <span class="cp-legend-item"><span class="cp-legend-dot cp-bar-negative"></span>Negative</span>
1716	      </div>
1717	    </div>`;
1718	  }
1719	
1720	  body.innerHTML = metricsHtml + chartHtml;
1721	}
